var channels = {};
var ga4rows = (ga4.rows || []);
for (var i = 0; i < ga4rows.length; i++) {
  var rv = ga4rows[i].dimensionValues || [];
  var mv = ga4rows[i].metricValues || [];
  var ch = (rv[0] && rv[0].value) ? rv[0].value : 'Other';
  channels[ch] = {
    s: parseInt((mv[0]&&mv[0].value)?mv[0].value:0),
    c: parseFloat((mv[1]&&mv[1].value)?mv[1].value:0),
    r: parseFloat((mv[2]&&mv[2].value)?mv[2].value:0)
  };
}
var ts=0, tr=0;
for (var k in channels) { ts+=channels[k].s; tr+=channels[k].r; }
var org = channels['Organic Search'] || {s:0,r:0,c:0};

// === CURRENT: GSC ===
var gRows = ($('GSC Queries').first().json.rows || []);
var tc=0, ti=0, posSum=0;
for (var j=0; j<gRows.length; j++) {
  tc+=gRows[j].clicks;
  ti+=gRows[j].impressions;
  posSum+=gRows[j].position;
}
var avgPos = gRows.length>0 ? (posSum/gRows.length).toFixed(1) : '0';
var avgCtr = ti>0 ? ((tc/ti)*100).toFixed(1) : '0';

// === CURRENT: YM ===
var ymData = $('YM Data').first().json;
var ymOrders = (ymData.pager && ymData.pager.total) ? ymData.pager.total : 0;

