var pg = pgRaw.result || pgRaw[0] || pgRaw;
var noTitle = parseInt(pg.without_any_title || 0);
var withTitle = parseInt(pg.with_ru_title || 0);
var totalTicker = parseInt(pg.total_ticker_pages || 0);
