  if (!hasPrev || p===null||p===undefined) return '';
  var diff = curr - p;
  var s = diff>=0?'+':'';
  return ' ('+s+diff+(unit||')+')';
}
function df(curr, p, unit) {
  if (!hasPrev || p===null||p===undefined) return '';
  var diff = (curr-p).toFixed(1);
  var s = diff>=0?'+':'';
  return ' ('+s+diff+(unit||'')+')';
}

